import{_ as a,o as e,c as r,ag as d}from"./chunks/framework.CvgP6Fyv.js";const m=JSON.parse('{"title":"XML インポート","description":"","frontmatter":{},"headers":[],"relativePath":"guide/xml-import.md","filePath":"guide/xml-import.md"}'),o={name:"guide/xml-import.md"};function l(h,t,i,s,n,c){return e(),r("div",null,[...t[0]||(t[0]=[d('<h1 id="xml-インポート" tabindex="-1">XML インポート <a class="header-anchor" href="#xml-インポート" aria-label="Permalink to &quot;XML インポート&quot;">​</a></h1><p>既存の ConMas i-Reporter XML ファイルを読み込んで、クラスターエディタで再編集できます。</p><hr><h2 id="対応する-xml" tabindex="-1">対応する XML <a class="header-anchor" href="#対応する-xml" aria-label="Permalink to &quot;対応する XML&quot;">​</a></h2><p>ConMas i-Reporter Designer で書き出した <strong>帳票テンプレート XML</strong> に対応しています。</p><div class="info custom-block"><p class="custom-block-title">ファイルサイズ上限</p><p>最大 <strong>50MB</strong> まで読み込み可能です。</p></div><hr><h2 id="インポート手順" tabindex="-1">インポート手順 <a class="header-anchor" href="#インポート手順" aria-label="Permalink to &quot;インポート手順&quot;">​</a></h2><h3 id="_1-ファイルをアップロード" tabindex="-1">1. ファイルをアップロード <a class="header-anchor" href="#_1-ファイルをアップロード" aria-label="Permalink to &quot;1. ファイルをアップロード&quot;">​</a></h3><p>トップ画面のアップロードエリアに <code>.xml</code> ファイルをドラッグ&amp;ドロップ、またはクリックして選択します。</p><p>Excel (<code>.xlsx</code>) と同じアップロードエリアですが、拡張子 <code>.xml</code> を検出すると自動的にインポートモードに切り替わります。</p><h3 id="_2-自動パース" tabindex="-1">2. 自動パース <a class="header-anchor" href="#_2-自動パース" aria-label="Permalink to &quot;2. 自動パース&quot;">​</a></h3><p>XML の構造が解析され、以下の情報が復元されます:</p><table tabindex="0"><thead><tr><th>項目</th><th>内容</th></tr></thead><tbody><tr><td>シート構造</td><td>セクション・ページ構成</td></tr><tr><td>クラスター</td><td>名前・タイプ・位置・サイズ</td></tr><tr><td>パラメータ</td><td>各クラスターの inputParameters</td></tr><tr><td>読み取り専用</td><td>ReadOnly フラグ</td></tr></tbody></table><h3 id="_3-クラスターエディタで編集" tabindex="-1">3. クラスターエディタで編集 <a class="header-anchor" href="#_3-クラスターエディタで編集" aria-label="Permalink to &quot;3. クラスターエディタで編集&quot;">​</a></h3><p>インポートが完了すると、AI 解析後と同じクラスターエディタ画面が表示されます。Excel アップロード時と同様に、すべての編集操作が利用できます。</p><hr><h2 id="使いどころ" tabindex="-1">使いどころ <a class="header-anchor" href="#使いどころ" aria-label="Permalink to &quot;使いどころ&quot;">​</a></h2><table tabindex="0"><thead><tr><th>シーン</th><th>説明</th></tr></thead><tbody><tr><td><strong>既存帳票の修正</strong></td><td>Designer で作った XML を微調整したいとき</td></tr><tr><td><strong>テンプレートの再利用</strong></td><td>既存帳票をベースに新しい帳票を作りたいとき</td></tr><tr><td><strong>AI 解析結果の確認</strong></td><td>以前エクスポートした XML を再読み込みして確認</td></tr></tbody></table><hr><h2 id="excel-フローとの違い" tabindex="-1">Excel フローとの違い <a class="header-anchor" href="#excel-フローとの違い" aria-label="Permalink to &quot;Excel フローとの違い&quot;">​</a></h2><table tabindex="0"><thead><tr><th></th><th>Excel アップロード</th><th>XML インポート</th></tr></thead><tbody><tr><td>AI 解析</td><td>必要（自動実行）</td><td>不要（クラスター情報が XML に含まれる）</td></tr><tr><td>プレビュー画面</td><td>あり</td><td>スキップ（直接エディタへ）</td></tr><tr><td>PDF プレビュー</td><td>Excel から生成</td><td>XML 内の PDF データを使用</td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title">Excel → XML → 再インポートも可能</p><p>一度 XML をダウンロードした後、再度インポートして編集を続けることもできます。作業を中断・再開する際に便利です。</p></div>',23)])])}const b=a(o,[["render",l]]);export{m as __pageData,b as default};
